     1→import { test, expect, Page } from '@playwright/test';
     2→
     3→const BASE_URL = process.env.BASE_URL || 'https://ohmydoc.vercel.app';
     4→
     5→const RESUME_TEXT = `
     6→Alex Rivera
     7→alex.rivera@email.com · (555) 123-4567 · San Francisco, CA · linkedin.com/in/alexrivera
     8→
     9→SUMMARY
    10→Full-stack software engineer with 7 years of experience building scalable web applications.
    11→Passionate about clean code, user experience, and developer tooling.
    12→
    13→EXPERIENCE
    14→
    15→Senior Software Engineer — Acme Corp (2021–Present)
    16→• Led development of a microservices architecture serving 2M+ daily active users
    17→• Reduced API latency by 40% through caching and database query optimization
    18→• Mentored a team of 4 junior engineers and conducted weekly code reviews
    19→
    20→Software Engineer — Bright Labs (2019–2021)
    21→• Built React-based dashboard used by 500+ enterprise clients
    22→• Integrated third-party payment APIs (Stripe, PayPal) handling $10M/month in transactions
    23→• Wrote comprehensive unit and integration tests achieving 90% code coverage
    24→
    25→EDUCATION
    26→B.S. Computer Science — University of California, Berkeley (2019)
    27→Dean's List, GPA 3.8/4.0
    28→
    29→SKILLS
    30→Languages: JavaScript, TypeScript, Python, Go
    31→Frameworks: React, Node.js, Express, Django
    32→Tools: Docker, Kubernetes, AWS, PostgreSQL, Redis, Git
    33→`.trim();
    34→
    35→const COVER_LETTER_TEXT = `
    36→Alex Rivera
    37→alex.rivera@email.com · San Francisco, CA
    38→
    39→March 4, 2026
    40→
    41→Hiring Manager
    42→TechVision Inc.
    43→123 Innovation Drive
    44→San Francisco, CA 94102
    45→
    46→Dear Hiring Manager,
    47→
    48→I am writing to express my strong interest in the Senior Software Engineer position at TechVision Inc.
    49→With seven years of experience building high-performance web applications and a proven track record
    50→of delivering impactful engineering solutions, I am confident I would make a valuable addition to your team.
    51→
    52→In my current role at Acme Corp, I architected a distributed microservices system that scaled to serve
    53→over two million daily active users while maintaining 99.9% uptime. I thrive in collaborative environments
    54→and enjoy mentoring junior developers to help them grow their technical skills and professional confidence.
    55→
    56→TechVision's commitment to innovation in AI-assisted developer tooling aligns perfectly with my passion
    57→for improving developer experience. I am particularly excited about the opportunity to contribute to
    58→your next-generation IDE features.
    59→
    60→Thank you for considering my application. I look forward to discussing how my background and skills
    61→can contribute to TechVision's continued success.
    62→
    63→Sincerely,
    64→Alex Rivera
    65→`.trim();
    66→
    67→// ─── Helpers ────────────────────────────────────────────────────────────────
    68→
    69→async function getTextarea(page: Page) {
    70→  return page.locator('textarea');
    71→}
    72→
    73→/**
    74→ * Reliably fill a textarea and wait for Vue's reactive model to update.
    75→ * Uses click + fill + value verification to avoid intermittent fill() issues.
    76→ */
    77→async function fillTextarea(page: Page, text: string): Promise<void> {
    78→  const textarea = page.locator('textarea');
    79→  await textarea.click();
    80→  await textarea.fill(text);
    81→  // Wait for Vue reactivity to process the input event
    82→  await page.waitForTimeout(300);
    83→  // Verify the value was actually set
    84→  const value = await textarea.inputValue();
    85→  if (value.length < 10 && text.length > 10) {
    86→    // Retry once if fill didn't work
    87→    await textarea.click();
    88→    await textarea.fill(text);
    89→    await page.waitForTimeout(500);
    90→  }
    91→}
    92→
    93→async function getFormatButton(page: Page) {
    94→  return page.getByRole('button', { name: /format my resume/i });
    95→}
    96→
    97→/**
    98→ * Wait for AI formatting to complete OR for an error state to appear.
    99→ * Returns 'success' | 'api_error' | 'timeout'.
   100→ * Uses a short-circuit: if error text appears within 15s we don't wait 90s.
   101→ * @param successText Optional text to look for in the preview to confirm success.
   102→ *                    Defaults to 'Alex Rivera'. Pass null to use generic detection.
   103→ */
   104→async function waitForFormattingOutcome(
   105→  page: Page,
   106→  successText: string | null = 'Alex Rivera'
   107→): Promise<'success' | 'api_error' | 'timeout'> {
   108→  const deadline = Date.now() + 90_000;
   109→  const errorPhrases = [
   110→    'api key is not configured',
   111→    'api key not configured',
   112→    'not configured',
   113→    'try again',
   114→    'error',
   115→    'failed',
   116→  ];
   117→
   118→  while (Date.now() < deadline) {
   119→    // Check for success
   120→    if (successText) {
   121→      const textVisible = await page.getByText(successText, { exact: false }).isVisible().catch(() => false);
   122→      if (textVisible) return 'success';
   123→    } else {
   124→      // Generic check: placeholder gone + Format button back to idle state
   125→      const placeholderGone = !(await page.getByText('Your formatted document will appear here.').isVisible().catch(() => true));
   126→      const btnIdle = await page.getByRole('button', { name: /format my resume/i }).isVisible().catch(() => false);
   127→      if (placeholderGone && btnIdle) return 'success';
   128→    }
   129→
   130→    // Check for API error fast
   131→    const bodyText = (await page.locator('body').innerText().catch(() => '')).toLowerCase();
   132→    if (errorPhrases.some(phrase => bodyText.includes(phrase))) {
   133→      return 'api_error';
   134→    }
   135→
   136→    await page.waitForTimeout(1000);
   137→  }
   138→  return 'timeout';
   139→}
   140→
   141→// ─── 1. Basic Load ───────────────────────────────────────────────────────────
   142→
   143→test('1a. Page title is OhMyDoc', async ({ page }) => {
   144→  await page.goto(BASE_URL);
   145→  await expect(page).toHaveTitle(/OhMyDoc/i);
   146→});
   147→
   148→test('1b. Textarea is visible and accepts input', async ({ page }) => {
   149→  await page.goto(BASE_URL);
   150→  const textarea = await getTextarea(page);
   151→  await expect(textarea).toBeVisible();
   152→  await textarea.fill('test input');
   153→  await expect(textarea).toHaveValue('test input');
   154→});
   155→
   156→test('1c. Format button is disabled when textarea is empty', async ({ page }) => {
   157→  await page.goto(BASE_URL);
   158→  const textarea = await getTextarea(page);
   159→  await expect(textarea).toHaveValue('');
   160→  const btn = await getFormatButton(page);
   161→  await expect(btn).toBeDisabled();
   162→});
   163→
   164→test('1d. Right panel shows placeholder text initially', async ({ page }) => {
   165→  await page.goto(BASE_URL);
   166→  await expect(page.getByText('Your formatted document will appear here.')).toBeVisible();
   167→});
   168→
   169→test('1e. No critical console errors on load', async ({ page }) => {
   170→  const errors: string[] = [];
   171→  page.on('console', msg => {
   172→    if (msg.type() === 'error') errors.push(msg.text());
   173→  });
   174→  await page.goto(BASE_URL);
   175→  await page.waitForLoadState('networkidle');
   176→  const critical = errors.filter(e =>
   177→    !e.includes('favicon') &&
   178→    !e.includes('net::ERR') &&
   179→    !e.includes('ERR_BLOCKED') &&
   180→    !e.includes('extension')
   181→  );
   182→  expect(critical, `Critical console errors: ${critical.join(', ')}`).toHaveLength(0);
   183→});
   184→
   185→// ─── 2. Happy Path — Resume ──────────────────────────────────────────────────
   186→
   187→test('2. Happy path — resume formatting', async ({ page }) => {
   188→  test.slow();
   189→  await page.goto(BASE_URL);
   190→
   191→  await fillTextarea(page, RESUME_TEXT);
   192→
   193→  const formatBtn = await getFormatButton(page);
   194→  await expect(formatBtn).toBeEnabled();
   195→  await formatBtn.click();
   196→
   197→  // Button should show loading state
   198→  await expect(page.getByRole('button', { name: /formatting/i })).toBeVisible({ timeout: 10_000 });
   199→
   200→  const outcome = await waitForFormattingOutcome(page);
   201→
   202→  // If API key is missing, fail with a clear message
   203→  if (outcome === 'api_error') {
   204→    const bodyText = await page.locator('body').innerText();
   205→    const hasApiKeyError = /api key is not configured|api key not configured|not configured/i.test(bodyText);
   206→    if (hasApiKeyError) {
   207→      throw new Error(
   208→        '[BUG] Deployment misconfiguration: "OpenAI API key is not configured." ' +
   209→        'The Vercel deployment is missing the required AI API key environment variable. ' +
   210→        'AI formatting cannot function.'
   211→      );
   212→    }
   213→    throw new Error(`AI formatting returned an error. Page text: ${bodyText.substring(0, 300)}`);
   214→  }
   215→
   216→  expect(outcome, 'Formatting timed out after 90s').toBe('success');
   217→
   218→  // Name should be visible
   219→  await expect(page.getByText('Alex Rivera', { exact: false })).toBeVisible();
   220→
   221→  // No raw XML tags in visible content
   222→  const bodyText = await page.locator('body').innerText();
   223→  expect(bodyText, 'Raw XML tags found in rendered preview').not.toMatch(/<\/?[a-z][^>]*>/);
   224→
   225→  // Button should return to normal
   226→  await expect(page.getByRole('button', { name: /format my resume/i })).toBeVisible({ timeout: 5_000 });
   227→});
   228→
   229→// ─── 3. Happy Path — Cover Letter ───────────────────────────────────────────
   230→
   231→test('3. Happy path — cover letter formatting', async ({ page }) => {
   232→  test.slow();
   233→  await page.goto(BASE_URL);
   234→
   235→  await fillTextarea(page, COVER_LETTER_TEXT);
   236→
   237→  const formatBtn = await getFormatButton(page);
   238→  await expect(formatBtn).toBeEnabled();
   239→  await formatBtn.click();
   240→
   241→  // Use generic detection: placeholder gone + Format button back to idle
   242→  const outcome = await waitForFormattingOutcome(page, null);
   243→
   244→  if (outcome === 'api_error') {
   245→    const bodyText = await page.locator('body').innerText();
   246→    const hasApiKeyError = /api key is not configured|api key not configured|not configured/i.test(bodyText);
   247→    if (hasApiKeyError) {
   248→      throw new Error(
   249→        '[BUG] Deployment misconfiguration: "OpenAI API key is not configured." ' +
   250→        'Cover letter formatting cannot function.'
   251→      );
   252→    }
   253→    throw new Error(`AI formatting returned an error. Page text: ${bodyText.substring(0, 300)}`);
   254→  }
   255→
   256→  expect(outcome, 'Cover letter formatting timed out after 90s').toBe('success');
   257→
   258→  // Verify the formatted preview is visible (not placeholder) and TechVision appears
   259→  await expect(page.getByText('Your formatted document will appear here.')).not.toBeVisible();
   260→  await expect(page.getByText('TechVision', { exact: false })).toBeVisible({ timeout: 10_000 });
   261→
   262→  const bodyText = await page.locator('body').innerText();
   263→  expect(bodyText, 'Raw XML tags found in rendered preview').not.toMatch(/<\/?[a-z][^>]*>/);
   264→});
   265→
   266→// ─── 4. Mutation Warning ─────────────────────────────────────────────────────
   267→
   268→test('4. Mutation/divergence warning element exists in DOM', async ({ page }) => {
   269→  test.slow();
   270→  await page.goto(BASE_URL);
   271→
   272→  await fillTextarea(page, RESUME_TEXT);
   273→  await (await getFormatButton(page)).click();
   274→
   275→  const outcome = await waitForFormattingOutcome(page);
   276→
   277→  if (outcome === 'api_error') {
   278→    const bodyText = await page.locator('body').innerText();
   279→    if (/api key is not configured|not configured/i.test(bodyText)) {
   280→      throw new Error(
   281→        '[BUG] Deployment misconfiguration: Cannot test divergence warning — API key not configured.'
   282→      );
   283→    }
   284→  }
   285→
   286→  if (outcome !== 'success') {
   287→    throw new Error(`Formatting did not complete successfully (outcome: ${outcome})`);
   288→  }
   289→
   290→  // Check for warning/alert elements in DOM (may be hidden)
   291→  const warningSelectors = [
   292→    '[class*="warning"]',
   293→    '[class*="diverge"]',
   294→    '[class*="mutation"]',
   295→    '[role="alert"]',
   296→    '[class*="yellow"]',
   297→    '[class*="caution"]',
   298→    '[class*="banner"]',
   299→  ];
   300→
   301→  let warningFound = false;
   302→  for (const selector of warningSelectors) {
   303→    if (await page.locator(selector).count() > 0) {
   304→      warningFound = true;
   305→      break;
   306→    }
   307→  }
   308→  const html = await page.content();
   309→  const hasDivergenceText = /diverge|mutation|content may have been changed|modified/i.test(html);
   310→
   311→  console.log(`Divergence/mutation warning present in DOM: ${warningFound || hasDivergenceText}`);
   312→  // Informational — passes regardless (warning only shows if divergence > 5%)
   313→  expect(true).toBe(true);
   314→});
   315→
   316→// ─── 5. PDF Export ───────────────────────────────────────────────────────────
   317→
   318→test('5. PDF Export button triggers window.print()', async ({ page }) => {
   319→  test.slow();
   320→  await page.goto(BASE_URL);
   321→
   322→  // Export PDF button should be disabled initially
   323→  const exportBtn = page.getByRole('button', { name: /export pdf/i });
   324→  await expect(exportBtn).toBeDisabled();
   325→
   326→  // Format a document first
   327→  await fillTextarea(page, RESUME_TEXT);
   328→  await (await getFormatButton(page)).click();
   329→
   330→  const outcome = await waitForFormattingOutcome(page);
   331→
   332→  if (outcome === 'api_error') {
   333→    const bodyText = await page.locator('body').innerText();
   334→    if (/api key is not configured|not configured/i.test(bodyText)) {
   335→      throw new Error(
   336→        '[BUG] Deployment misconfiguration: Cannot test PDF Export — API key not configured. ' +
   337→        'Export PDF button remains disabled because formatting never completes.'
   338→      );
   339→    }
   340→  }
   341→
   342→  expect(outcome, 'Formatting timed out before PDF export test').toBe('success');
   343→
   344→  // Export PDF button should now be enabled
   345→  await expect(exportBtn).toBeEnabled({ timeout: 10_000 });
   346→
   347→  // Intercept window.print()
   348→  let printCalled = false;
   349→  await page.exposeFunction('__testPrintCalled', () => { printCalled = true; });
   350→  await page.evaluate(() => {
   351→    window.print = () => {
   352→      (window as any).__testPrintCalled();
   353→    };
   354→  });
   355→
   356→  await exportBtn.click();
   357→  await page.waitForTimeout(1000);
   358→  expect(printCalled, 'window.print() was not called when Export PDF was clicked').toBe(true);
   359→});
   360→
   361→// ─── 6. Error / Validation States ────────────────────────────────────────────
   362→
   363→test('6a. Empty textarea keeps Format button disabled', async ({ page }) => {
   364→  await page.goto(BASE_URL);
   365→  const btn = await getFormatButton(page);
   366→  await expect(btn).toBeDisabled();
   367→  const textarea = await getTextarea(page);
   368→  await expect(textarea).toHaveValue('');
   369→  await expect(btn).toBeDisabled();
   370→});
   371→
   372→test('6b. Short input (<50 chars) shows validation error or keeps button disabled', async ({ page }) => {
   373→  await page.goto(BASE_URL);
   374→  const textarea = await getTextarea(page);
   375→  await textarea.fill('hello world test');
   376→
   377→  const btn = await getFormatButton(page);
   378→  if (await btn.isEnabled()) {
   379→    await btn.click();
   380→    // Should show a validation/error message
   381→    await page.waitForTimeout(2000);
   382→    const bodyText = await page.locator('body').innerText();
   383→    const hasValidationMsg = /too short|minimum|at least|characters|error|please provide/i.test(bodyText);
   384→    const errorCount = await page.locator('[class*="error"], [role="alert"]').count();
   385→    expect(
   386→      hasValidationMsg || errorCount > 0,
   387→      `Expected validation message for short input, body text: ${bodyText.substring(0, 200)}`
   388→    ).toBeTruthy();
   389→  } else {
   390→    // Button disabled for short text — also valid behaviour
   391→    await expect(btn).toBeDisabled();
   392→  }
   393→});
   394→
   395→// ─── 7. Skeleton Loading ─────────────────────────────────────────────────────
   396→
   397→test('7. Skeleton appears during loading and disappears after', async ({ page }) => {
   398→  test.slow();
   399→  await page.goto(BASE_URL);
   400→
   401→  await fillTextarea(page, RESUME_TEXT);
   402→  await (await getFormatButton(page)).click();
   403→
   404→  // Check for skeleton/shimmer/pulse shortly after clicking
   405→  const skeletonLocator = page.locator(
   406→    '[class*="skeleton"], [class*="shimmer"], [class*="animate-pulse"], [class*="loading"]'
   407→  );
   408→
   409→  const skeletonAppearedOrMissed = await skeletonLocator.first().isVisible({ timeout: 10_000 }).catch(() => false);
   410→  console.log(`Skeleton visible during loading: ${skeletonAppearedOrMissed}`);
   411→
   412→  const outcome = await waitForFormattingOutcome(page);
   413→
   414→  if (outcome === 'api_error') {
   415→    const bodyText = await page.locator('body').innerText();
   416→    if (/api key is not configured|not configured/i.test(bodyText)) {
   417→      throw new Error(
   418→        '[BUG] Deployment misconfiguration: Cannot fully test skeleton lifecycle — API key not configured. ' +
   419→        `Skeleton appeared during loading: ${skeletonAppearedOrMissed}`
   420→      );
   421→    }
   422→  }
   423→
   424→  expect(outcome, 'Formatting timed out before skeleton disappear check').toBe('success');
   425→
   426→  // After completion, skeleton should not be visible
   427→  const skeletonVisible = await skeletonLocator.first().isVisible().catch(() => false);
   428→  expect(skeletonVisible, 'Skeleton still visible after formatting completed').toBe(false);
   429→});
   430→
   431→// ─── 8. Sample Content ───────────────────────────────────────────────────────
   432→
   433→/**
   434→ * OhMyDoc provides sample content either via a dedicated "Load Sample" button
   435→ * (preferred UX) or as textarea placeholder text showing an example resume.
   436→ * These tests cover both patterns.
   437→ */
   438→
   439→test('8a. Sample content is available to first-time visitors', async ({ page }) => {
   440→  await page.goto(BASE_URL);
   441→
   442→  // Check for a dedicated sample button first
   443→  const sampleBtn = page.getByRole('button', { name: /sample/i })
   444→    .or(page.getByRole('link', { name: /sample/i }))
   445→    .or(page.getByText(/try sample|load sample|use sample|sample resume/i));
   446→
   447→  const hasSampleBtn = await sampleBtn.first().isVisible({ timeout: 3_000 }).catch(() => false);
   448→
   449→  if (hasSampleBtn) {
   450→    console.log('Sample content: dedicated button found');
   451→    expect(hasSampleBtn).toBe(true);
   452→    return;
   453→  }
   454→
   455→  // Fallback: check for example/sample content in textarea placeholder
   456→  const textarea = await getTextarea(page);
   457→  const placeholder = await textarea.getAttribute('placeholder');
   458→  const hasExampleInPlaceholder = /example|jane smith|resume|software engineer/i.test(placeholder ?? '');
   459→  console.log(`Sample content: placeholder shows example? ${hasExampleInPlaceholder}. Placeholder: "${placeholder?.substring(0, 100)}"`);
   460→
   461→  // Also check page HTML for any sample-related elements
   462→  const html = await page.content();
   463→  const hasSampleInHtml = /sample|try it|load example/i.test(html);
   464→
   465→  expect(
   466→    hasSampleBtn || hasExampleInPlaceholder || hasSampleInHtml,
   467→    'Expected either a sample button OR example content in textarea placeholder'
   468→  ).toBeTruthy();
   469→});
   470→
   471→test('8b. Sample content (if button exists) populates textarea and enables Format button', async ({ page }) => {
   472→  await page.goto(BASE_URL);
   473→
   474→  const sampleBtn = page.getByRole('button', { name: /sample/i })
   475→    .or(page.getByRole('link', { name: /sample/i }))
   476→    .or(page.getByText(/try sample|load sample|use sample|sample resume/i));
   477→
   478→  const hasSampleBtn = await sampleBtn.first().isVisible({ timeout: 3_000 }).catch(() => false);
   479→
   480→  if (!hasSampleBtn) {
   481→    // No dedicated sample button — document observation and pass
   482→    console.log('[OBSERVATION] No dedicated "Load Sample" button found. Sample content is shown as textarea placeholder only.');
   483→    console.log('Recommendation: add a "Try Sample" button so users can load sample content with one click.');
   484→    expect(true).toBe(true); // informational
   485→    return;
   486→  }
   487→
   488→  await sampleBtn.first().click();
   489→
   490→  // Textarea should now have content
   491→  const textarea = await getTextarea(page);
   492→  const value = await textarea.inputValue();
   493→  expect(value.length, 'Sample content did not populate the textarea').toBeGreaterThan(50);
   494→
   495→  // Format button should be enabled after loading sample
   496→  const formatBtn = await getFormatButton(page);
   497→  await expect(formatBtn).toBeEnabled({ timeout: 5_000 });
   498→});
   499→
   500→test('8c. Sample content (pasted manually from placeholder) can be formatted end-to-end', async ({ page }) => {
   501→  test.slow();
   502→  await page.goto(BASE_URL);
   503→
   504→  // Try dedicated sample button first
   505→  const sampleBtn = page.getByRole('button', { name: /sample/i })
   506→    .or(page.getByRole('link', { name: /sample/i }))
   507→    .or(page.getByText(/try sample|load sample|use sample|sample resume/i));
   508→
   509→  const hasSampleBtn = await sampleBtn.first().isVisible({ timeout: 3_000 }).catch(() => false);
   510→
   511→  const textarea = await getTextarea(page);
   512→
   513→  if (hasSampleBtn) {
   514→    await sampleBtn.first().click();
   515→    const value = await textarea.inputValue();
   516→    expect(value.length).toBeGreaterThan(50);
   517→  } else {
   518→    // Use the sample resume text as a proxy for what a first-time user would paste
   519→    const sampleContent = `Jane Smith
   520→jane@email.com · Toronto, ON
   521→
   522→Software Engineer with 8 years of experience in full-stack development.
   523→Skilled in React, Node.js, Python, and cloud infrastructure.
   524→
   525→EXPERIENCE
   526→Senior Engineer — CloudTech Inc (2020–Present)
   527→• Built scalable APIs serving 1M+ requests per day
   528→• Reduced infrastructure costs by 30% through optimization
   529→
   530→EDUCATION
   531→B.Sc. Computer Science — University of Toronto (2016)
   532→
   533→SKILLS
   534→JavaScript, TypeScript, Python, React, Node.js, AWS, Docker`;
   535→    await fillTextarea(page, sampleContent);
   536→    console.log('[OBSERVATION] No "Load Sample" button found — using hardcoded sample text to test formatting flow.');
   537→  }
